package com.aadil.jobtracker.security;import io.jsonwebtoken.Claims;import io.jsonwebtoken.Jwts;import io.jsonwebtoken.io.Decoders;import io.jsonwebtoken.security.Keys;import jakarta.annotation.PostConstruct;import org.springframework.beans.factory.annotation.Value;import org.springframework.security.core.userdetails.UserDetails;import org.springframework.stereotype.Component;import javax.crypto.SecretKey;import java.util.Date;@Componentpublic class JwtUtility {    @Value("${jwt.secret}")    private String secret;    @Value("${jwt.expiration}")    private Long jwtExpiration;    private SecretKey key;    @PostConstruct    private void runFirst(){        this.key = Keys.hmacShaKeyFor(Decoders.BASE64.decode(secret));    }    public String generateToken (UserDetails userDetails){        return Jwts.builder().subject(userDetails.getUsername())                .signWith(key)                .issuedAt(new Date()).expiration(new Date(System.currentTimeMillis() + jwtExpiration))                .claim("Roles", UserRoles.USER).compact();    }    public Claims parseClaims (String token){        return Jwts.parser().verifyWith(key)                .build().parseSignedClaims(token).getPayload();    }    public String extractUsername (String token){        return parseClaims(token).getSubject();    }    public boolean isTokenValid (String token, UserDetails userDetails){        String username = userDetails.getUsername();        return username.equals(userDetails.getUsername()) && !isTokenExpired (token);    }    private boolean isTokenExpired(String token) {        return parseClaims(token).getExpiration().before(new Date());    }}